--
-- Table structure for table `gate_incident_history`
--

DROP TABLE IF EXISTS `gate_incident_history`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `gate_incident_history` (
  `history_id` bigint NOT NULL AUTO_INCREMENT,
  `incident_id` bigint NOT NULL,
  `action_code` varchar(64) NOT NULL,
  `previous_status` enum('OPEN','ACKED','RESOLVED','IGNORED') DEFAULT NULL,
  `next_status` enum('OPEN','ACKED','RESOLVED','IGNORED') DEFAULT NULL,
  `actor_role` varchar(32) DEFAULT NULL,
  `actor_user_id` bigint DEFAULT NULL,
  `note` text,
  `evidence_media_id` bigint DEFAULT NULL,
  `snapshot_before_json` json DEFAULT NULL,
  `snapshot_after_json` json DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`history_id`),
  KEY `ix_gate_incident_history_incident` (`incident_id`,`created_at`),
  KEY `ix_gate_incident_history_action` (`action_code`,`created_at`),
  KEY `ix_gate_incident_history_actor` (`actor_user_id`,`created_at`),
  CONSTRAINT `fk_gate_incident_history_incident` FOREIGN KEY (`incident_id`) REFERENCES `gate_incidents` (`incident_id`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
