--
-- Table structure for table `gate_incidents`
--

DROP TABLE IF EXISTS `gate_incidents`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `gate_incidents` (
  `incident_id` bigint NOT NULL AUTO_INCREMENT,
  `session_id` bigint DEFAULT NULL,
  `site_id` bigint NOT NULL,
  `lane_id` bigint DEFAULT NULL,
  `device_id` bigint DEFAULT NULL,
  `severity` enum('INFO','WARN','CRITICAL') NOT NULL,
  `status` enum('OPEN','ACKED','RESOLVED','IGNORED') NOT NULL DEFAULT 'OPEN',
  `incident_type` varchar(64) NOT NULL,
  `title` varchar(255) NOT NULL,
  `detail` text,
  `source_key` varchar(191) DEFAULT NULL,
  `snapshot_json` json DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `resolved_at` datetime DEFAULT NULL,
  `resolution_action` varchar(64) DEFAULT NULL,
  `resolved_by_user_id` bigint DEFAULT NULL,
  `resolved_by_role` varchar(32) DEFAULT NULL,
  `evidence_media_id` bigint DEFAULT NULL,
  `last_signal_at` datetime DEFAULT NULL,
  PRIMARY KEY (`incident_id`),
  KEY `fk_gate_incidents_session` (`session_id`),
  KEY `fk_gate_incidents_lane` (`lane_id`),
  KEY `fk_gate_incidents_device` (`device_id`),
  KEY `ix_gate_incidents_status_created` (`status`,`created_at`),
  KEY `ix_gate_incidents_site_lane` (`site_id`,`lane_id`),
  KEY `ix_gate_incidents_site_device` (`site_id`,`device_id`),
  KEY `ix_gate_incidents_severity_created` (`severity`,`created_at`),
  KEY `ix_gate_incidents_source_key` (`source_key`),
  KEY `ix_gate_incidents_status_updated` (`status`,`updated_at`),
  KEY `ix_gate_incidents_site_status_created` (`site_id`,`status`,`created_at`),
  KEY `ix_gate_incidents_resolved_by_user` (`resolved_by_user_id`),
  CONSTRAINT `fk_gate_incidents_device` FOREIGN KEY (`device_id`) REFERENCES `gate_devices` (`device_id`),
  CONSTRAINT `fk_gate_incidents_lane` FOREIGN KEY (`lane_id`) REFERENCES `gate_lanes` (`lane_id`),
  CONSTRAINT `fk_gate_incidents_session` FOREIGN KEY (`session_id`) REFERENCES `gate_passage_sessions` (`session_id`),
  CONSTRAINT `fk_gate_incidents_site` FOREIGN KEY (`site_id`) REFERENCES `parking_sites` (`site_id`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

