  `lane_id` bigint NOT NULL,
  `direction` enum('ENTRY','EXIT') NOT NULL,
  `status` enum('OPEN','WAITING_READ','WAITING_DECISION','APPROVED','WAITING_PAYMENT','DENIED','PASSED','TIMEOUT','CANCELLED','ERROR') NOT NULL DEFAULT 'OPEN',
