--
-- Table structure for table `gate_read_events`
--

DROP TABLE IF EXISTS `gate_read_events`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `gate_read_events` (
  `read_event_id` bigint NOT NULL AUTO_INCREMENT,
  `session_id` bigint DEFAULT NULL,
  `site_id` bigint NOT NULL,
  `lane_id` bigint NOT NULL,
  `device_id` bigint NOT NULL,
  `read_type` enum('ALPR','RFID','SENSOR') NOT NULL,
  `direction` enum('ENTRY','EXIT') NOT NULL,
  `occurred_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `plate_raw` varchar(32) DEFAULT NULL,
  `plate_compact` varchar(32) DEFAULT NULL,
  `rfid_uid` varchar(64) DEFAULT NULL,
  `sensor_state` enum('PRESENT','CLEARED','TRIGGERED') DEFAULT NULL,
  `payload_json` json DEFAULT NULL,
  `source_media_id` bigint DEFAULT NULL,
  `raw_ocr_text` text,
  `ocr_confidence` decimal(5,4) DEFAULT NULL,
  `camera_frame_ref` varchar(255) DEFAULT NULL,
  `crop_ref` varchar(255) DEFAULT NULL,
  `source_device_code` varchar(64) DEFAULT NULL,
  `source_capture_ts` datetime(3) DEFAULT NULL,
  `request_id` varchar(64) DEFAULT NULL,
  `idempotency_key` varchar(64) DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`read_event_id`),
  UNIQUE KEY `uq_gate_reads_site_idem` (`site_id`,`idempotency_key`),
  KEY `fk_gate_reads_lane` (`lane_id`),
  KEY `ix_gate_reads_session` (`session_id`),
  KEY `ix_gate_reads_site_lane_time` (`site_id`,`lane_id`,`occurred_at`),
  KEY `ix_gate_reads_site_type_time` (`site_id`,`read_type`,`occurred_at`),
  KEY `ix_gate_reads_device_time` (`device_id`,`occurred_at`),
  KEY `ix_gate_reads_media` (`source_media_id`),
  KEY `ix_gate_reads_source_device_time` (`source_device_code`,`source_capture_ts`),
  CONSTRAINT `fk_gate_reads_device` FOREIGN KEY (`device_id`) REFERENCES `gate_devices` (`device_id`),
  CONSTRAINT `fk_gate_reads_lane` FOREIGN KEY (`lane_id`) REFERENCES `gate_lanes` (`lane_id`),
  CONSTRAINT `fk_gate_reads_session` FOREIGN KEY (`session_id`) REFERENCES `gate_passage_sessions` (`session_id`),
  CONSTRAINT `fk_gate_reads_site` FOREIGN KEY (`site_id`) REFERENCES `parking_sites` (`site_id`),
  CONSTRAINT `fk_gate_reads_source_media` FOREIGN KEY (`source_media_id`) REFERENCES `gate_read_media` (`media_id`)
) ENGINE=InnoDB AUTO_INCREMENT=34 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

