--
-- Table structure for table `gate_read_media`
--

DROP TABLE IF EXISTS `gate_read_media`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `gate_read_media` (
  `media_id` bigint NOT NULL AUTO_INCREMENT,
  `site_id` bigint NOT NULL,
  `lane_id` bigint DEFAULT NULL,
  `device_id` bigint DEFAULT NULL,
  `storage_kind` enum('UPLOAD','URL','INLINE','MOCK','UNKNOWN') NOT NULL DEFAULT 'UNKNOWN',
  `storage_provider` varchar(32) NOT NULL DEFAULT 'LOCAL',
  `media_url` varchar(1024) DEFAULT NULL,
  `file_path` varchar(1024) DEFAULT NULL,
  `bucket_name` varchar(255) DEFAULT NULL,
  `object_key` varchar(1024) DEFAULT NULL,
  `object_etag` varchar(255) DEFAULT NULL,
  `mime_type` varchar(128) DEFAULT NULL,
  `sha256` varchar(64) DEFAULT NULL,
  `width_px` int DEFAULT NULL,
  `height_px` int DEFAULT NULL,
  `metadata_json` json DEFAULT NULL,
  `captured_at` datetime DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`media_id`),
  KEY `fk_gate_read_media_device` (`device_id`),
  KEY `ix_gate_read_media_site_created` (`site_id`,`created_at`),
  KEY `ix_gate_read_media_site_device_time` (`site_id`,`device_id`,`captured_at`),
  KEY `ix_gate_read_media_lane_time` (`lane_id`,`captured_at`),
  KEY `ix_gate_read_media_sha256` (`sha256`),
  KEY `ix_gate_read_media_bucket_key` (`bucket_name`,`object_key`(255)),
  KEY `ix_gate_read_media_provider` (`storage_provider`,`created_at`),
